import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.BRIUyvy5.js";const _=JSON.parse('{"title":"股癌 每週摘要 (2026-W21)","description":"","frontmatter":{},"headers":[],"relativePath":"reports/guai/2026-W21.md","filePath":"reports/guai/2026-W21.md"}'),s={name:"reports/guai/2026-W21.md"};function e(p,r,g,i,l,h){return a(),o("div",null,[...r[0]||(r[0]=[n('<h1 id="股癌-每週摘要-2026-w21" tabindex="-1">股癌 每週摘要 (2026-W21) <a class="header-anchor" href="#股癌-每週摘要-2026-w21" aria-label="Permalink to &quot;股癌 每週摘要 (2026-W21)&quot;">​</a></h1><h2 id="_2026-05-20" tabindex="-1">2026-05-20 <a class="header-anchor" href="#_2026-05-20" aria-label="Permalink to &quot;2026-05-20&quot;">​</a></h2><h1 id="ep663-5月20日" tabindex="-1">EP663 / 5月20日 <a class="header-anchor" href="#ep663-5月20日" aria-label="Permalink to &quot;EP663 / 5月20日&quot;">​</a></h1><h2 id="_1-市場概況" tabindex="-1">1. 市場概況 <a class="header-anchor" href="#_1-市場概況" aria-label="Permalink to &quot;1. 市場概況&quot;">​</a></h2><p><strong>市場近期呈現持續修正的態勢：</strong> 主持人觀察到市場在過去幾天確實有所調整，但他個人體感並不覺得修正非常劇烈，這主要是受惠於選股較為幸運 。雖然他在禮拜二稍微感覺到波動，但到了錄音當天資產淨值又重新回升，顯示強勢股依然具備極佳的韌性 。在這種環境下，投資者的獲利很大程度取決於是否持有正確的族群，而非大盤的整體走向 。</p><p><strong>被動元件成為目前盤面的獲利核心：</strong> 主持人指出近期被動元件族群表現極其優異，無論是 MLCC（積層陶瓷電容） 或是 鋁電容 都為他帶來了豐厚的報酬 。這類標的在過去幾天的漲勢非常快，反映出市場資金正快速向具備實質需求支撐的電子零組件靠攏 。目前的盤勢更像是族群間的輪動，而非全面的市場反轉 。</p><p><strong>健康的輪動行情優於全面噴發：</strong> 主持人認為資金在不同族群間流轉、輪流休息，比起萬物齊漲的瘋狂，是更為健康的市場狀態 。如果所有股票都同時噴發，反而會讓人開始擔心行情是否過熱或即將結束 。目前這種「有漲有跌」的節奏，能讓市場具備更長久的續航力 。</p><p><strong>市場出現大量「劣質籌碼」擾動：</strong> 盤面上近期出現許多被主持人戲稱為「快樂寶貝」的雜魚資金，這類資金喜歡在盤中亂鎖漲停卻缺乏實力 。這些劣質籌碼通常在隔天無法開高，甚至會直接砸盤亂殺，導致市場短期籌碼變得混亂 。投資者應識別出這些短期投機訊號，避免被這類不穩定的股價波動影響操作信心 。</p><p><strong>成本緩衝是應對回檔的最佳防禦：</strong> 對於早期就建立部位的投資者來說，目前的修正只是「獲利縮水」而非「本金虧損」，心態上會相對麻木 。由於先前拉出的獲利空間極大，即便市場出現 1% 到 3% 的跌幅，資深投資者通常也不會輕易降槓桿 。這種因成本優勢帶來的心理穩定感，是吃完大波段行情的關鍵 。</p><p><strong>AI 投資是目前市場的核心支柱：</strong> 只要 AI 相關的資本支出與投資沒有突然戛然而止，大盤整體的結構就不容易出現系統性崩盤 。目前的修正多半被視為多頭市場中的「長多拉回」，這在歷史經驗中是非常典型的盤整現象 。市場目前仍具備強勢族群與正確的產業題材，不應因短期的技術性回檔就過度看空 。</p><h2 id="_2-關注的股票" tabindex="-1">2. 關注的股票 <a class="header-anchor" href="#_2-關注的股票" aria-label="Permalink to &quot;2. 關注的股票&quot;">​</a></h2><p><strong>被動元件龍頭與漲價題材：</strong> 主持人證實 Panasonic（松下） 已正式對部分客戶發出漲價通知，這驗證了先前市場對產能排擠引發漲價的預期 。雖然漲價信並非發給所有客戶，但這類「點狀」漲價通常會隨後擴散至整個產業鏈 。目前市場對於這類具備漲價故事的標的極為買單，資金正積極卡位相關供應鏈 。</p><p><strong>ASIC 晶片設計（聯發科與博通）：</strong> 供應鏈中關於 Google TPU 晶片的分配出現新變數，有報告指出 博通（Broadcom） 在下一代晶片開發中可能出現斷檔 。然而，主持人根據管道得知博通可能會推出一種「雙拼」式的 Big Sunfish 晶片，類似 Apple 的 Ultra 晶片設計 。這類高階設計的異動將直接影響載板與封裝廠的權重，是未來獲利的關鍵看點 。</p><p><strong>NVIDIA 供應鏈與改料風波：</strong> 儘管市場曾因 NVIDIA 晶片改料與延後的消息而恐慌，但主持人認為這只是產品開發中的常見延誤 。NVIDIA 本身依然按照其產品地圖（Roadmap）在推進，長線的基本面並未因短期技術調整而受損 。對於這類「老 AI」標的，市場的提款行為更偏向資金調節，而非產業終結 。</p><p><strong>記憶體標的（美光）：</strong> 在記憶體族群中，主持人目前僅持有 美光（Micron） 。他認為記憶體產業目前處於極佳的狀態，即便股價短期回檔也不代表趨勢結束 。他建議投資者應專注於龍頭廠商的長期產能配置，而非被每日微小的報價波動干擾判斷 。</p><p><strong>光通訊設備與技術門檻：</strong> 雖然光通訊族群近期表現較軟，但主持人強調其長期的成長性與技術門檻依然極高 。他認為這類標的目前處於「被虐」的震盪期，但歷史經驗顯示這類標的往往在低谷後會再次噴向新高 。投資者應參考過去如 Astera Labs 的走勢，理解高波動是這類標的的標配 。</p><p><strong>低估值的防守型標的：</strong> 市場中仍有一些交易在 10 倍左右本益比的「防守型」股票，這類標的在回檔時展現了極佳的抗跌性 。當市場動能減弱時，這類有實質財報與獲利支撐的標的，往往能成為資金的避風港 。投資者可以適度在投資組合中配置這類標的，以優化整體夏普率 。</p><h2 id="_3-其他財經消息及知識" tabindex="-1">3. 其他財經消息及知識 <a class="header-anchor" href="#_3-其他財經消息及知識" aria-label="Permalink to &quot;3. 其他財經消息及知識&quot;">​</a></h2><p><strong>系統化減重與健康投資的體悟：</strong> 主持人在不到兩個月內成功將體重從 84 公斤降至 78 公斤，並強調這是一場系統化的投資 。除了輔助針劑外，他透過大量的網球、重量訓練與增加日常步行（帶小孩）來維持肌肉量並減少脂肪 。他認為減重後的體感舒適度不輸戒菸，且能顯著解決長期的身體發炎與酸痛問題 。</p><p><strong>物理治療與正確發力的重要性：</strong> 透過物理治療師的診斷，主持人發現過往認為「舒服」的坐姿或睡姿，其實正是害身體發炎的元兇 。正確的身體調整需要喚醒核心肌肉，並讓肌肉間相互配合去做伸展與收縮，而非單純的拉筋 。這與投資邏輯相似：最舒適的慣性行為往往暗藏風險，必須主動學習正確的發力與體系 。</p><p><strong>產能排擠（Crowding Out）的商業邏輯：</strong> 當國際大廠如 Panasonic 為了獲取更高毛利而將產能轉向 AI 等高階應用時，會導致原本的標準品（鳥料）供需失衡 。這種現象導致大廠不再願意為了填補產能而去承接低價訂單，進而引發整體的漲價潮 。這套邏輯正同時發生在記憶體（HBM 排擠 DDR4）與被動元件產業中 。</p><p><strong>廠商掃貨現貨市場的信號意義：</strong> 台灣大廠近期被觀察到在現貨市場大舉掃除被動元件料件，主持人認為這絕非單純「炒股票」 。當老總看到供需失衡且價格即將上漲時，掃光市面上便宜的料件是極其理性的商業決策 。這種「貼牌出貨」或「搭售」的策略，能讓廠商在缺貨潮中極大化獲利 。</p><p><strong>傑文斯悖論（Jevons Paradox）在 AI 領域的應用：</strong> 雖然 AI 能讓寫程式或數據運算變得更有效率，但這反而會誘發更龐大且複雜的需求 。當獲取資訊與生成代碼的成本降低，社會整體的消耗量反而會呈倍數成長 。這解釋了為何技術進步不會消滅對半導體硬體的需求，反而會持續推升總體產量 。</p><p><strong>AI 代理人（Agent）在資訊篩選的實務：</strong> 主持人目前使用 Perplexity 等工具作為每日資訊爬取的 Agent，以提升大腦吸收資訊的效率 。雖然 AI 能整理資料，但哪一個資訊「有用」仍需透過人類的體感去判斷 。模型（如 Opus）的選擇比下指令（Prompt）更重要，能幫助投資者在海量數據中過濾出真正的關鍵訊號 。</p><h2 id="_4-q-a" tabindex="-1">4. Q&amp;A <a class="header-anchor" href="#_4-q-a" aria-label="Permalink to &quot;4. Q&amp;A&quot;">​</a></h2><p><strong>追求卓越的飛行願望與高昂薪資：</strong> 聽眾分享若考上培訓機師並成為副駕駛（FO），願捐出兩年薪水的 30% 。主持人估算 FO 的月薪可能高達 20 幾萬，這是一個非常慷慨的許願 。他祝願該聽眾能順利考取，並在未來駕駛飛機時能像投資一樣，專注於遠方的目標而非近處的晃動 。</p><p><strong>如何面對人比人氣死人的比較心態：</strong> 聽眾抱怨看到同儕開大槓桿賺得比自己快而感到挫折 。主持人指出，比較是快樂之賊，過度關注他人的績效只會讓自己的生活品質下降 。投資應專注於自身的資產成長與購買力，只要能持續跟隨大盤成長，就已經跑贏了絕大多數不投資的人 。</p><p><strong>資產變多後對「體驗」的投資觀念：</strong> 面對賺了錢卻捨不得花的聽眾，主持人建議應將資金拿去購買「人生的體驗」 。錢存在市場滾雖然幸福，但人生只有一次，買體驗（如旅遊或特定技能學習）帶來的記憶與成就感是無價的 。不要為了花錢而花錢，而是要找出能讓自己真正感到快樂的興趣去投入 。</p><p><strong>紅酒領域的氪金式學習法：</strong> 主持人近期透過大量購買市場上最貴的紅酒標本來學習，發現「價格標籤」是最好的老師 。透過研究最貴的年份與釀酒師，能最快掌握市場公認的品質標竿 。這種透過「金錢戰術」建立認知的方式，能讓他迅速了解一個產業的定價邏輯與核心價值 。</p><p><strong>關於「迷思」與強勢股的雷同：</strong> 投資者不應太容易受市場負面說法影響，尤其是針對長線成長的題材 。即便在修正過程中被虐，只要產業趨勢（如 AI 或光通訊）依然向上，回頭看這些震盪都只是噪音 。正確的應對方式是像飛機著陸一樣，視線要看往遠方的跑道末端，而非眼前的震盪 。</p><p><strong>儀式感在生活中的 CP 值：</strong> 聽眾分享為老婆安排海邊求婚的往事，主委對此大加讚賞 。他認為許多「鋼鐵直男」不懂浪漫，但其實學一下「八加九」的儀式感對維繫感情非常有幫助 。能在特定日子與另一半表示心意，其回報率（CP值）通常極高，是投資生活穩賺不賠的方式 。</p><p><strong>不輕易降槓桿的信心來源：</strong> 主持人坦言因獲利已經拉開極遠，即便遇到近期回檔也完全不擔心 。除非 AI 的投資趨勢徹底轉向，否則他會選擇留在場內直到故事結束 。投資者應培養能吃完一整段「大魚」的定力，而非被短期的價格跳動洗下車 。</p><p>這份摘要說明了在 AI 與零組件需求激增 的時刻，如何透過 系統化的身體管理與投資紀律，在瘋狂的市場中保持清醒並獲取回報。</p>',33)])])}const c=t(s,[["render",e]]);export{_ as __pageData,c as default};
